using System.Text;

namespace ExModem.Tools
{
    // 取姓名首字母分组键(A-Z / #)。中文用嵌入的全 CJK 首字母表(由 ExModem辅助工具/gen_pinyin.py 经 pypinyin 生成)。
    // 覆盖 GB2312 一级+二级及繁体字,二级字(如「馨」=X)不再误判为 #。
    public static class Pinyin
    {
        private const int Start = 0x4E00;

        public static char Initial(string? s)
        {
            if (string.IsNullOrEmpty(s)) return '#';
            char c = s[0];
            if (c >= 'A' && c <= 'Z') return c;
            if (c >= 'a' && c <= 'z') return (char)(c - 32);
            int cp = c;
            if (cp >= Start && cp < Start + Table.Length) return Table[cp - Start];
            return '#';
        }

        // U+4E00..U+9FA5 每个码位的拼音首字母(无拼音/非汉字为 '#')
        private const string Table =
            "#DQDFMSD#####XQBPFDWO##WHLYPCBJCC#DMBZPBZZ#";
    }
}
